parameters.jsCode:
// Extract the title, url and description fields
return $input.all().map(item => {
  return {
    json: {
      title: item.json.title,
      url: item.json.url,
      description: item.json.description
    }
  };
});

textOptions.schema:
{
  "type": "object",
  "properties": {
    "title": {
      "type": "string",
      "description": "Map this from the input"
    },
    "url": {
      "type": "string",
      "description": "Map this from the input"
    },
    "description": {
      "type": "string",
      "description": "Map this from the input"
    },
    "event_start_date": {
      "type": "string",
      "description": "The start date of the event in YYYY-MM-DD format."
    },
    "event_end_date": {
      "type": "string",
      "description": "The end date of the event in YYYY-MM-DD format."
    },
    "location": {
      "type": "string",
      "description": "The city/venue name or 'Online' if no physical location exists."
    },
    "location_type": {
      "type": "string",
      "enum": ["in_person", "hybrid", "online"],
      "description": "Classification of the event environment."
    },
    "status": {
      "type": "string",
      "enum": ["future_event", "past_event"],
      "description": "The temporal status based on the current date."
    }
  },
  "required": [
    "title",
    "url",
    "description",
    "event_start_date",
    "event_end_date",
    "location",
    "location_type",
    "status"
  ],
  "additionalProperties": false
}

parameters.jsCode:
return $input.all().map(item => {
  try {
    // This takes the 'output' text and turns it into a real JSON object
    const parsedData = JSON.parse(item.json.output);

    return {
      json: parsedData
    };
  } catch (error) {
    // This handles cases where the AI might have returned non-JSON text
    return {
      json: {
        error: "Could not parse AI output",
        raw: item.json.output
      }
    }
  }
});

